import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = "Unknown City",
  temperature = 0,
  condition = "Unknown",
  humidity = 0,
  windSpeed = 0,
  unit = "C",
  forecast = [],
}: Props) {
  return (
    <Card padding={24} shadow="md" radius="lg">
      <Stack gap={24}>
        <Stack gap={4} align="center">
          <Heading level={2}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">
            {condition}
          </Text>
        </Stack>

        <Stack gap={8} align="center">
          <Heading level={1} color="var(--ggui-color-primary-600)">
            {temperature}°{unit}
          </Heading>
        </Stack>

        <Stack direction="horizontal" justify="center" gap={32}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500)">Humidity</Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500)">Wind</Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider />

        <Stack direction="horizontal" justify="between" gap={16}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption">{item.day ?? 'N/A'}</Text>
              <Text size="lg">{item.icon ?? '?'}</Text>
              <Stack gap={2} align="center">
                <Text variant="label">{item.high ?? 0}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  TextArea, 
  RadioGroup, 
  Checkbox, 
  Progress, 
  Divider, 
  Box 
} from '@ggui-ai/design/primitives';

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: FormData) => void;
}

export default function GeneratedComponent({
  featureOptions = [
    "Dashboard Analytics",
    "Team Collaboration",
    "API Integration",
    "Custom Workflows",
    "Mobile App",
    "AI Assistance"
  ],
  satisfactionLabels = [
    "Very Unsatisfied",
    "Unsatisfied",
    "Neutral",
    "Satisfied",
    "Very Satisfied"
  ],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: ''
  });
  const [emailError, setEmailError] = useState('');

  const totalSteps = 4;

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const handleNext = () => {
    if (step === 1) {
      if (!validateEmail(data.email)) {
        setEmailError('Please enter a valid email address.');
        return;
      }
      setEmailError('');
    }
    setStep((s) => Math.min(s + 1, totalSteps + 1));
  };

  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const updateData = (key: keyof FormData, value: any) => setData((d) => ({ ...d, [key]: value }));

  const isNextDisabled = () => {
    if (step === 1) return !data.name.trim() || !data.email.trim();
    if (step === 2) return !data.satisfaction;
    return false;
  };

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="overline">Step {Math.min(step, totalSteps)} of {totalSteps}</Text>
          <Progress value={Math.min(step - 1, totalSteps) * (100 / totalSteps)} size="md" variant="default" />
        </Stack>

        <Box paddingY={16}>
          {step === 1 && (
            <Stack gap={16}>
              <Input label="Name" required value={data.name} onChange={(v) => updateData('name', v)} />
              <Input label="Email" required type="email" value={data.email} onChange={(v) => { updateData('email', v); setEmailError(''); }} error={emailError} />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup 
              label="How satisfied are you with our product?" 
              value={data.satisfaction} 
              onChange={(v) => updateData('satisfaction', v)}
              options={satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
            />
          )}

          {step === 3 && (
            <Stack gap={12}>
              <Text variant="label">Feature Interests</Text>
              {featureOptions.map(option => (
                <Checkbox 
                  key={option} 
                  label={option} 
                  checked={data.features.includes(option)}
                  onChange={(checked) => {
                    const newFeatures = checked 
                      ? [...data.features, option] 
                      : data.features.filter(f => f !== option);
                    updateData('features', newFeatures);
                  }}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea 
              label="Additional Comments (optional)" 
              value={data.comments} 
              onChange={(v) => updateData('comments', v)} 
              maxLength={500}
              showCount
            />
          )}

          {step > totalSteps && (
            <Stack gap={16}>
              <Heading level={3}>Review your answers</Heading>
              <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={8}>
                <Stack gap={8}>
                  <Text variant="bodySmall"><strong>Name:</strong> {data.name}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {data.email}</Text>
                  <Text variant="bodySmall"><strong>Satisfaction:</strong> {satisfactionLabels[parseInt(data.satisfaction) - 1]}</Text>
                  <Text variant="bodySmall"><strong>Features:</strong> {data.features.length > 0 ? data.features.join(', ') : 'None'}</Text>
                  <Text variant="bodySmall"><strong>Comments:</strong> {data.comments || 'N/A'}</Text>
                </Stack>
              </Box>
            </Stack>
          )}
        </Box>

        <Divider />
        <Stack direction="horizontal" justify="between" align="center">
          <Button variant="secondary" disabled={step === 1 || step > totalSteps} onClick={handleBack}>Back</Button>
          {step <= totalSteps ? (
            <Button disabled={isNextDisabled()} onClick={handleNext}>{step === totalSteps ? 'Review' : 'Next'}</Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit?.(data)}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Button, Input, Select, Box, Spacer, Divider } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Props {
  tasks: Task[];
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent({
  tasks: initialTasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' }
  ],
  onTaskUpdate
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleUpdate = (action: string, taskId: string, data: any) => {
    if (onTaskUpdate) {
      onTaskUpdate({ action, taskId, data });
    }
  };

  const addTask = (colId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: colId,
      assignee: '??'
    };
    setTasks([...tasks, newTask]);
    handleUpdate('create', newTask.id!, newTask);
    setNewTaskTitle('');
    setIsAdding(null);
  };

  const moveTask = (taskId: string, newCol: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, column: newCol } : t));
    handleUpdate('move', taskId, { column: newCol });
  };

  const completedCount = tasks.filter(t => t.column === 'done').length;

  return (
    <Box padding={24}>
      <Stack direction="horizontal" gap={16} align="center">
        <Text variant="bodyLarge">Task Board</Text>
        <Text variant="bodySmall">Total: {tasks.length} | Completed: {completedCount}</Text>
      </Stack>
      <Spacer size={24} />
      <Stack direction="horizontal" gap={16} align="start">
        {columns.map(col => (
          <Box key={col.id} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8} style={{ width: 300 }}>
            <Text variant="label">{col.name} ({tasks.filter(t => t.column === col.id).length})</Text>
            <Spacer size={16} />
            <Stack gap={12}>
              {tasks.filter(t => t.column === col.id).map(task => (
                <Card key={task.id} padding={12} shadow="sm">
                  <Text weight="semibold">{task.title}</Text>
                  <Text variant="caption">Priority: {task.priority}</Text>
                  <Spacer size={8} />
                  <Stack direction="horizontal" gap={8}>
                    {columns.map(c => c.id !== task.column && (
                      <Button key={c.id} size="xs" variant="ghost" onClick={() => moveTask(task.id!, c.id!)}>
                        Move to {c.name}
                      </Button>
                    ))}
                  </Stack>
                </Card>
              ))}
            </Stack>
            <Spacer size={16} />
            {isAdding === col.id ? (
              <Stack gap={8}>
                <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                <Select label="Priority" value={newTaskPriority} onChange={(v: any) => setNewTaskPriority(v)} options={[
                  { value: 'low', label: 'Low' },
                  { value: 'medium', label: 'Medium' },
                  { value: 'high', label: 'High' }
                ]} />
                <Button size="sm" onClick={() => addTask(col.id!)}>Confirm</Button>
                <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
              </Stack>
            ) : (
              <Button size="sm" variant="outline" fullWidth onClick={() => setIsAdding(col.id!)}>+ Add Task</Button>
            )}
          </Box>
        ))}
      </Stack>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Heading, Input, Box, Divider, Badge } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-info-200, #a5f3fc)',
  'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
  'alkali-metal': 'var(--ggui-color-error-200, #fecaca)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'transition-metal': 'var(--ggui-color-success-200, #bbf7d0)',
  'halogen': 'var(--ggui-color-primary-100, #e0f2fe)',
  'default': 'var(--ggui-color-neutral-200, #e5e7eb)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filtered = useMemo(() => 
    elements.filter(e => 
      e.name?.toLowerCase().includes(search.toLowerCase()) || 
      e.symbol?.toLowerCase().includes(search.toLowerCase())
    ), [elements, search]);

  const categories = useMemo(() => Array.from(new Set(elements.map(e => e.category || 'default'))), [elements]);

  return (
    <Stack gap={24} padding={24}>
      <Card padding={16}>
        <Input 
          label="Search Elements"
          placeholder="Search by name or symbol..." 
          value={search} 
          onChange={setSearch}
        />
      </Card>

      <Box style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(18, 1fr)', 
        gap: '4px',
        maxWidth: '1200px',
        margin: '0 auto'
      }}>
        {filtered.map(el => (
          <button
            key={el.atomicNumber}
            type="button"
            onClick={() => setSelected(el)}
            style={{
              gridRow: el.row,
              gridColumn: el.col,
              aspectRatio: '1',
              backgroundColor: CATEGORY_COLORS[el.category || 'default'] || CATEGORY_COLORS.default,
              borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
              cursor: 'pointer',
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'center',
              alignItems: 'center',
              padding: '4px',
              border: selected?.atomicNumber === el.atomicNumber ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-neutral-300, #d1d5db)',
              transition: 'transform 0.2s',
              appearance: 'none'
            }}
          >
            <Text variant="caption">{el.atomicNumber}</Text>
            <Heading level={5}>{el.symbol}</Heading>
          </button>
        ))}
      </Box>

      <Stack direction="horizontal" gap={16} justify="center" wrap>
        {categories.map(cat => (
          <Stack key={cat} direction="horizontal" gap={8} align="center">
            <Box style={{ width: 12, height: 12, backgroundColor: CATEGORY_COLORS[cat] || CATEGORY_COLORS.default, borderRadius: 2 }} />
            <Text variant="caption">{cat}</Text>
          </Stack>
        ))}
      </Stack>

      {selected && (
        <Card padding={24}>
          <Heading level={3}>{selected.name}</Heading>
          <Divider margin={16} />
          <Stack direction="horizontal" gap={32}>
            <Stack gap={8}>
              <Text variant="label">Symbol</Text>
              <Text>{selected.symbol}</Text>
            </Stack>
            <Stack gap={8}>
              <Text variant="label">Atomic Number</Text>
              <Text>{selected.atomicNumber}</Text>
            </Stack>
            <Stack gap={8}>
              <Text variant="label">Atomic Weight</Text>
              <Text>{selected.atomicWeight}</Text>
            </Stack>
            <Stack gap={8}>
              <Text variant="label">Category</Text>
              <Badge variant="default">{selected.category}</Badge>
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Divider, 
  Text, 
  Heading, 
  Button, 
  Tabs, 
  Badge, 
  Icon 
} from '@ggui-ai/design/primitives';

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Product {
  id?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
}

interface Props {
  product?: Product;
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    product = {
      id: 'prod-001',
      name: 'Wireless Noise-Cancelling Headphones',
      price: 249.99,
      currency: 'USD',
      rating: 4.3,
      reviewCount: 128,
      stock: 12,
      description: 'Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.',
      specifications: [
        { key: 'Brand', value: 'AudioMax' },
        { key: 'Battery Life', value: '30 hours' }
      ],
      reviews: [
        { author: 'Alex M.', rating: 5, text: 'Best headphones I have ever owned.', date: '2026-03-01' }
      ]
    },
    onAddToCart = () => {}
  } = props;

  const [quantity, setQuantity] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleAddToCart = async () => {
    setIsSubmitting(true);
    try {
      await onAddToCart({ productId: product.id ?? '', quantity });
    } finally {
      setIsSubmitting(false);
    }
  };

  const isOutOfStock = (product.stock ?? 0) <= 0;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box background="var(--ggui-color-neutral-100)" borderRadius={12} padding={64} style={{ flex: 1, minWidth: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={3}>{product.name ?? 'Product'}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
            <Heading level={1}>{product.name ?? 'Unknown Product'}</Heading>
            <Text variant="bodyLarge" weight="bold">{product.currency} {product.price?.toFixed(2) ?? '0.00'}</Text>
            <Stack direction="horizontal" gap={4}>
              {[1, 2, 3, 4, 5].map((i) => (
                <Icon key={i} name="star" size={16} color={i <= Math.floor(product.rating ?? 0) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'} />
              ))}
              <Text variant="caption">({product.reviewCount ?? 0})</Text>
            </Stack>
            <Badge variant={(product.stock ?? 0) > 5 ? 'success' : 'warning'}>
              {(product.stock ?? 0) > 0 ? 'In Stock' : 'Out of Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Tabs 
          variant="line"
          items={[
            { 
              key: 'desc', 
              label: 'Description', 
              content: <Text>{product.description ?? 'No description available.'}</Text> 
            },
            { 
              key: 'specs', 
              label: 'Specifications', 
              content: (
                <Stack gap={8}>
                  {product.specifications?.map((spec: any, i: number) => (
                    <Stack key={i} direction="horizontal" gap={16}>
                      <Text variant="body" weight="medium" style={{ width: 120 }}>{spec.key}</Text>
                      <Text variant="body">{spec.value}</Text>
                    </Stack>
                  ))}
                </Stack>
              ) 
            },
            { 
              key: 'reviews', 
              label: 'Reviews', 
              content: (
                <Stack gap={16}>
                  {product.reviews?.map((review: any, i: number) => (
                    <Card key={i} padding={16}>
                      <Stack gap={4}>
                        <Text weight="semibold">{review.author} - {review.rating}/5</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">{review.date}</Text>
                        <Text>{review.text}</Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              ) 
            }
          ]}
        />

        <Divider />

        <Stack direction="horizontal" gap={16} align="center">
          <Stack direction="horizontal" gap={8} align="center">
            <Button variant="outline" size="sm" onClick={() => setQuantity(q => Math.max(1, q - 1))}>-</Button>
            <Text>{quantity}</Text>
            <Button variant="outline" size="sm" onClick={() => setQuantity(q => Math.min(product.stock ?? 1, q + 1))}>+</Button>
          </Stack>
          <Button 
            variant="primary" 
            loading={isSubmitting} 
            disabled={isOutOfStock || isSubmitting} 
            onClick={handleAddToCart}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Heading, Button, Box, Divider, Input } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages?: Message[];
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatWindow(props: Props) {
  const {
    title,
    currentUser,
    participantCount = 0,
    messages: initialMessages = [],
    onSendMessage
  } = props;

  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages(initialMessages);
  }, [initialMessages]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const { text, sender, timestamp } = event.detail;
      setMessages((prev) => [...prev, { sender, text, timestamp }]);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const payload = {
      text: inputValue,
      timestamp: new Date().toISOString(),
    };
    onSendMessage?.(payload);
    setMessages((prev) => [...prev, { sender: currentUser, ...payload }]);
    setInputValue('');
  };

  const groupMessages = (msgs: Message[]) => {
    const groups: { sender: string; msgs: Message[] }[] = [];
    msgs.forEach((m) => {
      const sender = m.sender ?? 'Unknown';
      if (groups.length > 0 && groups[groups.length - 1].sender === sender) {
        groups[groups.length - 1].msgs.push(m);
      } else {
        groups.push({ sender, msgs: [m] });
      }
    });
    return groups;
  };

  return (
    <Card padding={0} border={true}>
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount > 0 && (
            <Text variant="caption">{participantCount} participants</Text>
          )}
        </Stack>
      </Box>
      <Divider margin={0} />

      <Box 
        padding={16} 
        style={{ flex: 1, overflowY: 'auto', maxHeight: '400px' }}
      >
        <Stack gap={16} ref={scrollRef}>
          {groupMessages(messages).map((group, idx) => (
            <Stack key={idx} align={group.sender === currentUser ? 'end' : 'start'} gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
              {group.msgs.map((m, mIdx) => (
                <Box
                  key={mIdx}
                  paddingX={12}
                  paddingY={8}
                  borderRadius={8}
                  background={
                    group.sender === currentUser
                      ? 'var(--ggui-color-primary-600)'
                      : 'var(--ggui-color-surfaceVariant)'
                  }
                >
                  <Text color={group.sender === currentUser ? '#ffffff' : 'var(--ggui-color-onSurface)'}>
                    {m.text}
                  </Text>
                  <Text variant="caption" size="xs" color={group.sender === currentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}>
                    {new Date(m.timestamp ?? '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </Text>
                </Box>
              ))}
            </Stack>
          ))}
        </Stack>
      </Box>

      <Divider margin={0} />
      <Box padding={12} background="var(--ggui-color-surface)">
        <Stack direction="horizontal" gap={8} align="end">
          <Input 
            label="Message" 
            value={inputValue} 
            onChange={setInputValue} 
            placeholder="Type a message..."
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <Button onClick={handleSend} disabled={!inputValue.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Card, Text, Heading, Spacer, Divider } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Stock[];
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(false);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data?.stocks) setStocks(data.stocks);
      if (data?.lastUpdated) setLastUpdated(data.lastUpdated);
    };

    window.addEventListener('ggui:agent-data', handleData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleData as EventListener);
  }, []);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        <Divider />

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)'
        }}>
          {stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const color = isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card key={stock.symbol ?? index} border shadow="sm" padding={20}>
                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <div>
                      <Heading level={3}>{stock.symbol ?? '---'}</Heading>
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                    </div>
                    <Text variant="bodyLarge" weight="bold">
                      ${stock.price?.toFixed(2) ?? '0.00'}
                    </Text>
                  </Stack>

                  <Spacer size={8} />

                  <div style={{ color, display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                    <Text weight="medium" size="sm">
                      {isPositive ? '▲' : '▼'} {Math.abs(stock.change ?? 0).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                    </Text>
                  </div>
                </Stack>
              </Card>
            );
          })}
        </div>

        {stocks.length === 0 && (
          <Card padding={40} border={false} shadow="none" style={{ textAlign: 'center' }}>
            <Text color="var(--ggui-color-neutral-500, #6b7280)">No market data available</Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Checkbox, Toggle, Divider, Container } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string; 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0] ?? '',
    role: initialProfile.role ?? roleOptions[0] ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const next = () => setStep((s) => Math.min(s + 1, 3));
  const back = () => setStep((s) => Math.max(s - 1, 1));

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6, 24px)">
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="horizontal" justify="between">
            <Text variant="overline">Step {step} of 3</Text>
            <Text variant="caption">{Math.round((step / 3) * 100)}% Complete</Text>
          </Stack>

          <div style={{ height: 'var(--ggui-spacing-2, 8px)', background: 'var(--ggui-color-neutral-200, #e5e7eb)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)' }}>
            <div style={{ height: '100%', width: `${(step / 3) * 100}%`, background: 'var(--ggui-color-primary-600, #0284c7)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', transition: 'width 200ms ease' }} />
          </div>

          <Divider margin="var(--ggui-spacing-4, 16px)" />

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Profile Setup</Heading>
              <Input label="Name" required value={formData.name} onChange={(v) => setFormData({...formData, name: v})} />
              <Input label="Email" type="email" required value={formData.email} onChange={(v) => setFormData({...formData, email: v})} error={formData.email && !validateEmail(formData.email) ? 'Invalid format' : undefined} />
              <Text variant="label">Avatar</Text>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                {avatarOptions.map(emoji => (
                  <Button 
                    key={emoji} 
                    variant={formData.avatar === emoji ? 'primary' : 'outline'} 
                    size="sm"
                    onClick={() => setFormData({...formData, avatar: emoji})}
                  >
                    {emoji}
                  </Button>
                ))}
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Preferences</Heading>
              <Select 
                label="Role" 
                value={formData.role} 
                onChange={(v) => setFormData({...formData, role: v})} 
                options={roleOptions.map(r => ({ value: r, label: r }))} 
              />
              <Checkbox 
                label="Email Notifications" 
                checked={formData.emailNotifications} 
                onChange={(v) => setFormData({...formData, emailNotifications: v})} 
                description="Receive updates via email." 
              />
              <Toggle 
                label={`Theme: ${formData.theme === 'light' ? 'Light' : 'Dark'}`} 
                checked={formData.theme === 'dark'} 
                onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})} 
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Review & Confirm</Heading>
              <Card padding="var(--ggui-spacing-4, 16px)" radius="md" border={false} style={{ background: 'var(--ggui-color-neutral-100, #f3f4f6)' }}>
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="bodySmall"><b>Name:</b> {formData.name}</Text>
                  <Text variant="bodySmall"><b>Email:</b> {formData.email}</Text>
                  <Text variant="bodySmall"><b>Avatar:</b> {formData.avatar}</Text>
                  <Text variant="bodySmall"><b>Role:</b> {formData.role}</Text>
                  <Text variant="bodySmall"><b>Notifications:</b> {formData.emailNotifications ? 'On' : 'Off'}</Text>
                  <Text variant="bodySmall"><b>Theme:</b> {formData.theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}

          <Stack direction="horizontal" justify="between" style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
            <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

