import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Divider, Spacer, Container } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: { name: string; email: string; satisfaction: number; features: string[]; comments: string }) => void;
}

export default function GeneratedComponent({
  featureOptions = ["Dashboard Analytics", "Team Collaboration", "API Integration", "Custom Workflows", "Mobile App", "AI Assistance"],
  satisfactionLabels = ["Very Unsatisfied", "Unsatisfied", "Neutral", "Satisfied", "Very Satisfied"],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const totalSteps = 5;

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction !== 0;
    if (step === 3) return formData.features.length > 0;
    return true;
  };

  const handleNext = () => setStep((s) => Math.min(s + 1, totalSteps));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name') setErrors((prev) => ({ ...prev, name: value.trim() ? '' : 'Name is required' }));
    if (field === 'email') setErrors((prev) => ({ ...prev, email: validateEmail(value) ? '' : 'Invalid email address' }));
  };

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={24}>
        <Stack gap={16}>
          <Text variant="overline">Step {step} of {totalSteps}</Text>
          <Progress value={(step / totalSteps) * 100} size="sm" variant="default" />

          <Divider />

          {step === 1 && (
            <Stack gap={16}>
              <Heading level={3}>Basic Information</Heading>
              <Input label="Name" required value={formData.name} onChange={(v) => updateField('name', v)} error={errors.name} />
              <Input label="Email" type="email" required value={formData.email} onChange={(v) => updateField('email', v)} error={errors.email} />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with the product?"
                value={formData.satisfaction.toString()}
                onChange={(v) => updateField('satisfaction', parseInt(v))}
                options={satisfactionLabels.map((label, i) => ({ value: (i + 1).toString(), label }))}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={3}>Features Interest</Heading>
              <Text>What features are you most interested in?</Text>
              {featureOptions.map(feature => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={formData.features.includes(feature)}
                  onChange={() => toggleFeature(feature)}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={formData.comments}
                onChange={(v) => updateField('comments', v)}
                maxLength={500}
                showCount
                rows={4}
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap={16}>
              <Heading level={3}>Review</Heading>
              <Stack gap={8}>
                <Text><b>Name:</b> {formData.name}</Text>
                <Text><b>Email:</b> {formData.email}</Text>
                <Text><b>Rating:</b> {formData.satisfaction > 0 ? satisfactionLabels[formData.satisfaction - 1] : 'Not set'}</Text>
                <Text><b>Features:</b> {formData.features.join(', ') || 'None'}</Text>
                <Text><b>Comments:</b> {formData.comments || 'No comments'}</Text>
              </Stack>
            </Stack>
          )}

          <Spacer size={16} />
          <Stack direction="horizontal" gap={16} justify="between">
            <Button variant="secondary" disabled={step === 1} onClick={handleBack}>Back</Button>
            {step < totalSteps ? (
              <Button variant="primary" disabled={!isStepValid()} onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit?.(formData)}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Badge, Avatar, Spacer, Box, Divider } from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Task[];
  columns?: Column[];
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create', taskId?: string, data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    tasks: initialTasks = [],
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ],
    onTaskUpdate
  } = props;

  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  const handleCreateTask = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??'
    };
    const updatedTasks = [...tasks, newTask];
    setTasks(updatedTasks);
    onTaskUpdate?.({ action: 'create', data: newTask });
    setAddingToColumn(null);
    setNewTaskTitle('');
  };

  const moveTask = (taskId: string, targetColumn: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setTasks(updatedTasks);
    onTaskUpdate?.({ action: 'move', taskId, data: { column: targetColumn } });
  };

  return (
    <Box padding={24}>
      <Stack gap={24}>
        <Card padding={16}>
          <Stack direction="horizontal" gap={16} align="center">
            <Heading level={3}>Project Board</Heading>
            <Spacer size="flex" />
            <Text>Total: {totalTasks}</Text>
            <Text>Completed: {completedTasks}</Text>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={16} align="start" justify="start">
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-neutral-100)" padding={16} borderRadius={8} style={{ width: 300 }}>
              <Stack gap={16}>
                <Heading level={5}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>

                <Stack gap={12}>
                  {tasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        <Text variant="label">{task.title}</Text>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}>
                            {task.priority}
                          </Badge>
                          <Avatar name={task.assignee} size={24} />
                        </Stack>
                        <Divider margin={8} />
                        <Select 
                          value={task.column ?? ''} 
                          onChange={(v) => moveTask(task.id!, v)}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingToColumn === col.id ? (
                  <Card padding={12}>
                    <Stack gap={8}>
                      <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title..." />
                      <Select 
                        label="Priority"
                        value={newTaskPriority} 
                        onChange={(v) => setNewTaskPriority(v as any)}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Stack direction="horizontal" gap={8}>
                        <Button size="sm" onClick={() => handleCreateTask(col.id!)}>Add</Button>
                        <Button size="sm" variant="ghost" onClick={() => setAddingToColumn(null)}>Cancel</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setAddingToColumn(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements?: Array<Element>;
}

const CATEGORY_COLORS: Record<string, string> = {
  "nonmetal": "var(--ggui-color-primary-200, #bae6fd)",
  "noble-gas": "var(--ggui-color-info-200, #a5f3fc)",
  "alkali-metal": "var(--ggui-color-error-200, #fecaca)",
  "alkaline-earth-metal": "var(--ggui-color-warning-200, #fde68a)",
  "transition-metal": "var(--ggui-color-neutral-200, #e5e7eb)",
  "halogen": "var(--ggui-color-success-200, #bbf7d0)",
  "lanthanide": "var(--ggui-color-primary-100, #e0f2fe)",
  "actinide": "var(--ggui-color-primary-100, #e0f2fe)",
  "metal": "var(--ggui-color-neutral-300, #d1d5db)",
  "metalloid": "var(--ggui-color-neutral-300, #d1d5db)"
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filtered = useMemo(() => {
    if (!search) return elements;
    const lower = search.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(lower) ||
        e.symbol?.toLowerCase().includes(lower)
    );
  }, [elements, search]);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          label="Search Elements"
          placeholder="Search by name or symbol..." 
          value={search} 
          onChange={setSearch} 
          type="search"
        />

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: '4px',
          overflowX: 'auto'
        }}>
          {elements.map((el) => {
            const isVisible = filtered.includes(el);
            return (
              <Box
                key={el.atomicNumber}
                onClick={() => setSelected(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-neutral-100)',
                  cursor: 'pointer',
                  opacity: isVisible ? 1 : 0.2,
                  transition: 'opacity 0.2s',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  minHeight: '64px',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
                }}
              >
                <Text variant="caption" style={{ alignSelf: 'flex-start', padding: '0 4px' }}>{el.atomicNumber}</Text>
                <Text variant="bodyLarge" style={{ fontWeight: 'bold' }}>{el.symbol}</Text>
              </Box>
            );
          })}
        </Box>

        {selected && (
          <Card padding={24}>
            <Stack gap={8}>
              <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
              <Divider />
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

