    name?: string; 
    price?: number; 
    currency?: string; 
    rating?: number; 
    reviewCount?: number; 
    stock?: number; 
    description?: string; 
    specifications?: { key: string; value: string }[]; 
    reviews?: { author: string; rating: number; text: string; date: string }[] 
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    product = {
      id: 'prod-001',
      name: 'Wireless Noise-Cancelling Headphones',
      price: 249.99,
      currency: 'USD',
      rating: 4.3,
      reviewCount: 128,
      stock: 12,
      description: 'Premium wireless headphones with adaptive noise cancellation.',
      specifications: [{ key: 'Brand', value: 'AudioMax' }, { key: 'Battery Life', value: '30 hours' }],
      reviews: [{ author: 'Alex M.', rating: 5, text: 'Best headphones ever.', date: '2026-03-01' }]
    },
    onAddToCart
  } = props;

  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(false);

  const renderStars = (rating: number) => (
    <Stack direction="horizontal" gap={2}>
      {Array.from({ length: 5 }).map((_, i) => (
        <Text key={i} as="span" color={i < Math.floor(rating) ? "var(--ggui-color-warning-500)" : "var(--ggui-color-neutral-300)"}>
          ★
        </Text>
      ))}
    </Stack>
  );

  const handleAdd = () => {
    if (product.id && onAddToCart) {
      setLoading(true);
      onAddToCart({ productId: product.id, quantity });
      setTimeout(() => setLoading(false), 800);
    }
  };

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap align="start">
          <Box 
            style={{ flex: 1, minWidth: '300px', aspectRatio: '1/1', background: 'var(--ggui-color-surfaceVariant)' }} 
            borderRadius={12} 
            padding={64}
          >
            <Text align="center" weight="bold">{product.name}</Text>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{product.currency} {product.price?.toFixed(2)}</Text>
            <Stack direction="horizontal" gap={8} align="center">
              {renderStars(product.rating || 0)}
              <Text variant="caption">({product.reviewCount} reviews)</Text>
            </Stack>
            <Badge variant={product.stock && product.stock > 0 ? 'success' : 'error'}>
              {(product.stock ?? 0) > 0 ? ((product.stock ?? 0) > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>

            <Divider margin={8} />

            <Stack direction="horizontal" gap={16} align="center">
              <Button 
                variant="secondary" 
                size="sm" 
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
              >
                -
              </Button>
              <Text weight="medium">{quantity}</Text>
              <Button 
                variant="secondary" 
                size="sm" 
                onClick={() => setQuantity(Math.min(product.stock ?? 0, quantity + 1))}
              >
                +
              </Button>
              <Button 
                variant="primary" 
                onClick={handleAdd} 
                loading={loading} 
                disabled={(product.stock ?? 0) === 0}
              >
                Add to Cart
              </Button>
            </Stack>
          </Stack>
        </Stack>

        <Divider />

        <Stack gap={16}>
          <Heading level={3}>Details</Heading>
          <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
            <Text variant="body">{product.description}</Text>
          </Box>
        </Stack>

        <Stack gap={16}>
          <Heading level={3}>Specifications</Heading>
          {product.specifications?.map((spec, i) => (
            <Box key={i} paddingY={8} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
              <Text as="span" weight="semibold">{spec.key}: </Text>
              <Text as="span" color="var(--ggui-color-onSurfaceVariant)">{spec.value}</Text>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages?: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback on send */
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'You',
    participantCount = 0,
    messages = [],
    onSend,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    onSend?.({ text: inputValue, timestamp: new Date().toISOString() });
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    return new Date(isoString).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Card shadow="md" padding={0} radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '600px', overflow: 'hidden' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" align="center" justify="between">
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{title}</Text>
          {participantCount > 0 && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{participantCount} participants</Text>
          )}
        </Stack>
      </Box>

      <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>
        <Stack gap={16}>
          {messages.map((msg, index) => {
            const isOwn = msg.sender === currentUser;
            const showSender = index === 0 || messages[index - 1].sender !== msg.sender;

            return (
              <Stack key={index} align={isOwn ? 'end' : 'start'} gap={4}>
                {showSender && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={12}
                  background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                >
                  <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>
                    {msg.text}
                  </Text>
                </Box>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {formatTime(msg.timestamp)}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <div style={{ flex: 1 }}>
            <Input
              value={inputValue}
              onChange={setInputValue}
              placeholder="Type a message..."
              label=""
              onKeyDown={handleKeyDown}
            />
          </div>
          <Button variant="primary" onClick={handleSend} disabled={!inputValue.trim()}>
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks?: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard component displaying real-time stock information.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {
  const [data, setData] = useState<Stock[]>(stocks ?? []);
  const [timestamp, setTimestamp] = useState<string | undefined>(lastUpdated);

  // Subscribe to real-time updates via window event
  useEffect(() => {
    const handleData = (event: any) => {
      // Stream Contract: listen for ggui:agent-data
      if (event.detail) {
        if (Array.isArray(event.detail)) {
          setData(event.detail);
          setTimestamp(new Date().toISOString());
        } else if (event.detail.stocks) {
          setData(event.detail.stocks);
          setTimestamp(event.detail.lastUpdated || new Date().toISOString());
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  const formatPrice = (price?: number) =>
    price !== undefined ? `$${price.toFixed(2)}` : 'N/A';

  const formatPercent = (percent?: number) =>
    percent !== undefined ? `${Math.abs(percent).toFixed(2)}%` : '0.00%';

  return (
    <Box padding={24} background="var(--ggui-color-surface, #fafafa)" style={{ minHeight: '100vh' }}>
      <Stack gap={24}>
        {/* Header */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          {timestamp && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {new Date(timestamp).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        {/* Stock Grid - Responsive grid layout */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}>
          {data.map((stock, idx) => {
            const val = stock.change ?? 0;
            const isPositive = val >= 0;
            const color = isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card
                key={stock.symbol ?? idx}
                padding={20}
                border={true}
                style={{
                  borderColor: isPositive ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)',
                }}
              >
                <Stack gap={12}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name ?? '-'}</Text>
                  </Stack>
                  <Divider />
                  <Stack>
                    <Text size="3xl" weight="bold">{formatPrice(stock.price)}</Text>
                    <Text
                      variant="label"
                      style={{ color }}
                      weight="medium"
                    >
                      {isPositive ? '▲' : '▼'} {Math.abs(val).toFixed(2)} ({formatPercent(stock.changePercent)})
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>

        {data.length === 0 && (
          <Box padding={48} style={{ textAlign: 'center' }}>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No stock data available.</Text>
          </Box>
        )}
      </Stack>
    </Box>
  );
}

import React, { useState } from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Toggle, 
  Divider, 
  Container, 
  Box 
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions[0] ?? ''),
    role: initialProfile.role ?? (roleOptions[0] ?? ''),
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const next = () => setStep((s) => Math.min(s + 1, 3));
  const back = () => setStep((s) => Math.max(s - 1, 1));

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Profile Setup</Heading>
            <Input 
              label="Name" 
              value={formData.name} 
              onChange={(v) => setFormData({...formData, name: v})} 
              required 
            />
            <Input 
              label="Email" 
              type="email" 
              value={formData.email} 
              onChange={(v) => setFormData({...formData, email: v})} 
              error={formData.email && !validateEmail(formData.email) ? "Invalid email" : undefined} 
              required 
            />
            <Text variant="label">Avatar</Text>
            <Stack direction="horizontal" gap={12}>
              {avatarOptions.map((opt) => (
                <Button 
                  key={opt} 
                  variant={formData.avatar === opt ? 'primary' : 'outline'} 
                  onClick={() => setFormData({...formData, avatar: opt})}
                >
                  {opt}
                </Button>
              ))}
            </Stack>
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Heading level={3}>Preferences</Heading>
            <Select 
              label="Role" 
              value={formData.role} 
              onChange={(v) => setFormData({...formData, role: v})} 
              options={roleOptions.map(r => ({value: r, label: r}))} 
            />
            <Toggle 
              label="Email Notifications" 
              checked={formData.emailNotifications} 
              onChange={(v) => setFormData({...formData, emailNotifications: v})} 
            />
            <Toggle 
              label="Dark Theme" 
              checked={formData.theme === 'dark'} 
              onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})} 
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Heading level={3}>Review & Confirm</Heading>
            <Box padding={16} background="var(--ggui-color-neutral-100)" borderRadius={8}>
              <Stack gap={8}>
                <Text variant="bodySmall"><strong>Name:</strong> {formData.name}</Text>
                <Text variant="bodySmall"><strong>Email:</strong> {formData.email}</Text>
                <Text variant="bodySmall"><strong>Avatar:</strong> {formData.avatar}</Text>
                <Text variant="bodySmall"><strong>Role:</strong> {formData.role}</Text>
                <Text variant="bodySmall"><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                <Text variant="bodySmall"><strong>Theme:</strong> {formData.theme}</Text>
              </Stack>
            </Box>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="sm">
      <Card shadow="md" padding={24}>
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="caption">Step {step} of 3</Text>
            <Box background="var(--ggui-color-neutral-200)" borderRadius={4} paddingY={4} paddingX={0}>
              <Box background="var(--ggui-color-primary-600)" borderRadius={4} paddingY={4} style={{ width: `${(step / 3) * 100}%` }} />
            </Box>
          </Stack>
          {renderStep()}
          <Divider />
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
